update inventory_batch
product_id = #{productId}, batch_code = #{batchCode}, production_time = #{productionTime}, expiration_time = #{expirationTime}, stock_quantity = #{stockQuantity}, locked_quantity = #{lockedQuantity}, sold_quantity = #{soldQuantity}, status = #{status}, update_time = #{updateTime}, update_user = #{updateUser},
