mapper.select:
select b.*, p.name as productName, p.category_id as categoryId, p.price as basePrice
from inventory_batch b
left join product p on b.product_id = p.id

    and b.product_id = #{productId}
    and p.category_id = #{categoryId}
    and b.batch_code like concat('%', #{batchCode}, '%')
    and b.status = #{status}

order by b.expiration_time asc, b.id desc

