update inventory_batch
set locked_quantity = locked_quantity - #{quantity},
    update_time = now()
where id = #{batchId}
  and locked_quantity >= #{quantity}

update inventory_batch
set locked_quantity = locked_quantity - #{quantity},
    sold_quantity = sold_quantity + #{quantity},
    update_time = now()
where id = #{batchId}
  and locked_quantity >= #{quantity}
